/**
 * Model Sku
 * A SKU created in Zack's Retail (net-new). Lifecycle-managed.
 * The `sku_code_matches_state` check constraint enforces:
 * state=DRAFT  → code IS NULL
 * state≠DRAFT  → code IS NOT NULL
 * The service layer owns the transitions (see skuLifecycleService).
 */
export type Sku = $Result.DefaultSelection<Prisma.$SkuPayload>
/**
 * Model SkuActivity
 * State-transition audit log. Written by skuLifecycleService — no DB trigger,
 * because we want the service to own the who/why context (actor, reason).
 */
export type SkuActivity = $Result.DefaultSelection<Prisma.$SkuActivityPayload>
/**
 * Model SkuSize
 * Per-SKU size-label rows. Each SKU carries an ordered list of the sizes it
 * is sold in (e.g. "7", "7.5", "8", ...). `sort_order` controls display on
 * the size grid; `active` hides a size from new assignments without dropping
 * inventory rows that reference it. Matches the pre-migration SQLite shape
 * 1:1 with native Postgres types.
 */
export type SkuSize = $Result.DefaultSelection<Prisma.$SkuSizePayload>
/**
 * Model Inventory
 * Per-(SKU × size) on-hand + reserved state. One row per size when the SKU
 * has a size grid; `sku_size_id = null` for SKUs that don't (accessories,
 * single-variant items). `(sku_id, sku_size_id)` is unique so the pair is
 * the natural join key for mutations from adjustmentService / ticketService.
 */
export type Inventory = $Result.DefaultSelection<Prisma.$InventoryPayload>
