/**
 * Model SkuCodeSequence
 * Per-prefix auto-increment counter used by skuService.generateSkuCode and
 * purchaseOrderService for PO numbering. The upsert-and-read pattern
 * (`INSERT ... ON CONFLICT DO UPDATE SET next_val = next_val + 1`) maps to
 * Prisma's `upsert` cleanly: insert with next_val=1 on create, set
 * next_val = { increment: 1 } on update, then return the row.
 * 
 * Postgres sequences (`CREATE SEQUENCE`) would be faster but require one
 * sequence per prefix — which is unbounded. This table keeps all prefixes
 * in one place and lets the operator inspect / reset them directly.
 */
export type SkuCodeSequence = $Result.DefaultSelection<Prisma.$SkuCodeSequencePayload>
/**
 * Model AttributeDimension
 * One extensible facet (buyer, company, store_chain, discount_type, …).
 * Multi-value dims allow a SKU to carry more than one value (e.g. a SKU can
 * run two discount mechanics simultaneously). Single-value dims are enforced
 * at the service layer, not the DB, so cardinality can flip without migration.
 * 
 * Family scoping is many-to-many via `AttributeFamilyRule`. A dimension with
 * zero rule rows is **universal** — renders for every family. A dimension with
 * one or more rules renders only for families whose rule has `enabled=true`.
 * Required enforcement (`is_required` on the rule) is validated on SKU save.
 */
export type AttributeDimension = $Result.DefaultSelection<Prisma.$AttributeDimensionPayload>
/**
 * Model AttributeFamilyRule
 * One (dimension, family) rule row. Presence of ≥1 rule for a dimension flips
 * it from universal to family-scoped. `enabled=false` hides the dimension for
 * that family without deleting the row (preserves `is_required` + history).
 */
export type AttributeFamilyRule = $Result.DefaultSelection<Prisma.$AttributeFamilyRulePayload>
/**
 * Model AttributeValue
 * A value available within a dimension (e.g. buyer:zb, discount_type:pct_50).
 * `is_active=false` hides the value from new-assignment dropdowns but
 * preserves it for existing assignments and audit history.
 */
export type AttributeValue = $Result.DefaultSelection<Prisma.$AttributeValuePayload>
/**
 * Model SkuAttributeAssignment
 * Per-SKU classification. Composite PK makes re-assertion idempotent.
 * `assigned_by` tags source: `seed:keyword:<rule_hash>`, `seed:excel:<batch>`,
 * or an operator user id / email. Precedence (enforced in service layer):
 * operator-edit > seed:excel:* > seed:keyword:* > no row.
 */
export type SkuAttributeAssignment = $Result.DefaultSelection<Prisma.$SkuAttributeAssignmentPayload>
/**
 * Model EtlRunTable
 * One row per (run, source MDB table). Records row count + duration + status.
 */
export type EtlRunTable = $Result.DefaultSelection<Prisma.$EtlRunTablePayload>
/**
 * Model ReportTemplate
 * Reports module — saved/reusable report query (a.k.a. "template").
 * Captures (report_type + params) for later replay against fresh data.
 * Owner has full control; visibility='shared' grants read-only access to any
 * authenticated user. Runs/snapshots of frozen results live in a separate
 * table added in Phase 1.1 (docs/dev/plans/2026-04-22-report-templates-and-runs.md).
 */
export type ReportTemplate = $Result.DefaultSelection<Prisma.$ReportTemplatePayload>
/**
 * Model ReportRun
 * A frozen snapshot of a report run. Captured explicitly via "Save snapshot"
 * after reviewing a result (never auto-saved). Stores the full response
 * payload so the page can re-render exactly what was on screen at capture.
 * Envelope columns (rowCount, resultSizeBytes, reportTypeVersion) are
 * computed server-side so the list view does not deserialize the blob, and
 * so clients cannot lie about them.
 * Spec: docs/dev/plans/2026-04-22-report-templates-and-runs.md Phase 1.1.
 */
export type ReportRun = $Result.DefaultSelection<Prisma.$ReportRunPayload>
